const SKILL_KEYWORDS = [
  "Java",
  "Spring Boot",
  "React",
  "TypeScript",
  "JavaScript",
  "SQL",
  "PostgreSQL",
  "Docker",
  "AWS",
  "Python",
  "REST",
  "Microservices",
  "Testing",
  "CI/CD",
  "Git"
];

const RECOMMENDATION_BANK = [
  "Add measurable business impact to recent roles.",
  "Mirror the job description language for your strongest matching skills.",
  "Keep the summary focused on role, domain, and seniority.",
  "Group technical skills by category for faster recruiter scanning.",
  "Add one or two project bullets that show ownership from problem to result."
];

export type GeneratedAnalysis = {
  skills: string;
  experience: string;
  education: string;
  score: number;
  recommendations: string;
};

export const generateAnalysis = (
  file: File,
  jobDescription: string,
  focusSkills: string
): GeneratedAnalysis => {
  const sourceText = `${file.name} ${jobDescription} ${focusSkills}`.toLowerCase();
  const matchedSkills = SKILL_KEYWORDS.filter((skill) =>
    sourceText.includes(skill.toLowerCase())
  );

  const requestedSkills = focusSkills
    .split(",")
    .map((skill) => skill.trim())
    .filter(Boolean);

  const skills = Array.from(new Set([...matchedSkills, ...requestedSkills])).slice(0, 12);
  const hasJobDescription = jobDescription.trim().length > 80;
  const fileQualityBonus = file.type.includes("pdf") || file.name.endsWith(".docx") ? 8 : 3;
  const matchScore = Math.min(52, skills.length * 6);
  const score = Math.min(96, 34 + matchScore + fileQualityBonus + (hasJobDescription ? 10 : 0));

  const recommendations = RECOMMENDATION_BANK.filter((_, index) => {
    if (score >= 80) {
      return index < 3;
    }
    return index !== 0 || hasJobDescription;
  }).slice(0, 4);

  return {
    skills: JSON.stringify(skills.length ? skills : ["Resume review pending"]),
    experience: JSON.stringify([
      {
        section: "Experience",
        finding: hasJobDescription
          ? "Compared against the supplied job description."
          : "Upload saved; add a job description for sharper matching."
      }
    ]),
    education: JSON.stringify([
      {
        section: "Education",
        finding: "Education details will be parsed by the backend model when available."
      }
    ]),
    score,
    recommendations: JSON.stringify(recommendations)
  };
};

export const parseJsonList = (value?: string): string[] => {
  if (!value) {
    return [];
  }

  try {
    const parsed = JSON.parse(value);
    if (Array.isArray(parsed)) {
      return parsed.map((item) =>
        typeof item === "string" ? item : item.finding || JSON.stringify(item)
      );
    }
  } catch {
    return value
      .split(",")
      .map((item) => item.trim())
      .filter(Boolean);
  }

  return [];
};
